import React, { Component } from 'react';
import { properties } from '../properties/properties'

class Cardiology extends React.Component {

    constructor(props) {
        super(props);
        this.state = {  result: {}, screen: 1, emailHeader: "", assigned: [], remainPatients: []};
    }

    componentDidMount() {


        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + "cardiology", {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {
            //console.log(response);
            this.setState({result: response})
            //console.log(this.state.result)
          })
          .catch(err => {
            console.log(err);
          });

    }


    runManually = () => {
        this.setState({screen: 2})
        this.setState({emailHeader: document.getElementById("emailHeader").value})

        var remainPatients = []
        for (var index in this.state.result.admit) {
            var patients = this.state.result.admit[index].patients
            for (var indexJ in patients){
                var patient = patients[indexJ]
                patient.crane = this.state.result.admit[index].crane
                remainPatients.push(patient)
            }
        }
        console.log(remainPatients)
        this.setState({remainPatients: remainPatients})
    }

    runMoveToAssign = (evt) => {

        var assigned = this.state.assigned
        var remainPatients = this.state.remainPatients
        var removeIndex = -1
        var stopLoop = false

        //console.log(remainPatients)
        for (var i=0;i<remainPatients.length&&!stopLoop;i++) {
            //console.log(remainPatients[i].MRN)
            //console.log(evt.currentTarget.value)
            if (remainPatients[i].MRN === evt.currentTarget.value){
              //var assignPatient = {crane: remainPatients[i].crane, Team: document.getElementById("move_" + remainPatients[i].MRN).value, FromTeam: remainPatients[i].Team, MRN: remainPatients[i].MRN, CSN: remainPatients[i].CSN, OneLiner: remainPatients[i].OneLiner, Name: remainPatients[i].Name, Age: remainPatients[i].Age, Location: remainPatients[i].Location, Sex: remainPatients[i].Sex}
              var assignPatient = remainPatients[i];
              var fromTeam = remainPatients[i].Team
              assignPatient.Team = document.getElementById("move_" + remainPatients[i].MRN).value
              assignPatient.FromTeam = fromTeam
              var findTeam = this.state.result.team.filter(Record => Record.name === document.getElementById("move_" + remainPatients[i].MRN).value)
              assignPatient.appTeam = findTeam[0].appTeam
              assigned.push(assignPatient)
              removeIndex = i
              stopLoop = true
            }
        }
        if (removeIndex != -1)
            remainPatients.splice(removeIndex,1)
        this.setState({remainPatients: remainPatients})


        var slotTaking = []


        //var y = 0
        for (var index in assigned) {


            if (!assigned[index].appTeam) {
                if (assigned[index].crane) {
                    var fromTeam = slotTaking.filter(Record => Record.team == assigned[index].FromTeam).sort((a,b) => (a.order > b.order) ? 1 : -1)
                    var team = slotTaking.filter(Record => Record.team == assigned[index].Team).sort((a,b) => (a.order > b.order) ? 1 : -1)
                    var y = 0
                    for (var fromTeamIndex in fromTeam) {
                        if (fromTeam[fromTeamIndex].order === y) {
                            y = y + 1
                        }
                    }
                    for (var teamIndex in team) {
                        if (team[teamIndex].order === y) {
                            y = y + 1
                        }
                    }
                    slotTaking.push({team: assigned[index].FromTeam, order: y})
                    slotTaking.push({team: assigned[index].Team, order: y})


                    var minutes = 15 * y 
                    //var totalMinutes = 495 + minutes
                    //if (this.state.result.todayDay === 2) {
                        var totalMinutes = 510 + minutes
                    //} 
                    var minutePart = totalMinutes % 60
                    var hourPart = (totalMinutes - minutePart) / 60

                    var endMinutePart = (totalMinutes + 15) % 60
                    var endHourPart = (totalMinutes + 15 - endMinutePart) / 60


                    if (minutePart === 0) {
                        minutePart = "00"
                    }
                    if (endMinutePart === 0) {
                        endMinutePart = "00"
                    }

                    assigned[index].signoutTime =  hourPart + ":" + minutePart 
                    assigned[index].signoutTimeDetail = hourPart + ":" + minutePart + "-" + endHourPart + ":" + endMinutePart + ": "
                    y += 1
                } else {
                    assigned[index].signoutTime = "7:00 "
                    assigned[index].signoutTimeDetail = "7:00 "
                    assigned[index].crane = false
                }
            } else {
                assigned[index].signoutTime = "7:00"
                assigned[index].signoutTimeDetail = "7:00 "
                assigned[index].crane = false
            }
        }

        console.log(assigned)

        this.setState({assigned: assigned})
    }


    runMove = (evt) => {
        var assigned = this.state.assigned
        var findAssign = {}
        var removeIndex = -1
        for(var k=0;k<assigned.length;k++) {
          if (assigned[k].MRN === evt.currentTarget.value) {
            assigned[k].Team = document.getElementById("move_" + evt.currentTarget.value).value
            var findTeam = this.state.result.team.filter(Record => Record.name === document.getElementById("move_" + evt.currentTarget.value).value)
            assigned[k].appTeam = findTeam[0].appTeam
            findAssign = assigned[k]
            removeIndex = k
          }
        }
        if (removeIndex != -1)
            assigned.splice(removeIndex,1)
        assigned.push(findAssign)

        var slotTaking = []
        //var y = 0
        for (var index in assigned) {
            if (!assigned[index].appTeam) {
                if (assigned[index].crane) {

                    var fromTeam = slotTaking.filter(Record => Record.team == assigned[index].FromTeam).sort((a,b) => (a.order > b.order) ? 1 : -1)
                    var team = slotTaking.filter(Record => Record.team == assigned[index].Team).sort((a,b) => (a.order > b.order) ? 1 : -1)
                    var y = 0
                    for (var fromTeamIndex in fromTeam) {
                        if (fromTeam[fromTeamIndex].order === y) {
                            y = y + 1
                        }
                    }
                    for (var teamIndex in team) {
                        if (team[teamIndex].order === y) {
                            y = y + 1
                        }
                    }
                    slotTaking.push({team: assigned[index].FromTeam, order: y})
                    slotTaking.push({team: assigned[index].Team, order: y})

                    var minutes = 15 * y 
                    //var totalMinutes = 495 + minutes
                    //if (this.state.result.todayDay === 2) {
                        var totalMinutes = 510 + minutes
                    //} 
                    var minutePart = totalMinutes % 60
                    var hourPart = (totalMinutes - minutePart) / 60

                    var endMinutePart = (totalMinutes + 15) % 60
                    var endHourPart = (totalMinutes + 15 - endMinutePart) / 60

                    if (minutePart === 0) {
                        minutePart = "00"
                    }
                    if (endMinutePart === 0) {
                        endMinutePart = "00"
                    }

                    assigned[index].signoutTime =  hourPart + ":" + minutePart 
                    assigned[index].signoutTimeDetail = hourPart + ":" + minutePart + "-" + endHourPart + ":" + endMinutePart + ": "

                    y += 1
                } else {
                    assigned[index].signoutTime = "7:00 "
                    assigned[index].signoutTimeDetail = "7:00 "
                }
            } else {
                assigned[index].signoutTime = "7:00"
                assigned[index].signoutTimeDetail = "7:00 "
            }
        }

        this.setState({assigned: assigned})
    }

    runConfirm = () => {
        this.setState({screen: 3})
    }

    copyFormatted = (html) => {
        // Create container for the HTML
        // [1]
        var container = document.createElement('div')
        container.innerHTML = html

        // Hide element
        // [2]
        container.style.position = 'fixed'
        container.style.pointerEvents = 'none'
        //container.style.opacity = 0

        // Detect all style sheets of the page
        var activeSheets = Array.prototype.slice.call(document.styleSheets)
          .filter(function (sheet) {
            return !sheet.disabled
          })

        // Mount the container to the DOM to make `contentWindow` available
        // [3]
        document.body.appendChild(container)

        // Copy to clipboard
        // [4]
        window.getSelection().removeAllRanges()

        var range = document.createRange()
        range.selectNode(container)
        window.getSelection().addRange(range)

        // [5.1]
        document.execCommand('copy')

        // [5.2]
        for (var i = 0; i < activeSheets.length; i++) activeSheets[i].disabled = true

        // [5.3]
        document.execCommand('copy')

        // [5.4]
        for (var i = 0; i < activeSheets.length; i++) activeSheets[i].disabled = false

        // Remove the container
        // [6]
        document.body.removeChild(container)
      }


      downloadPdf = (html) => {

        const element = document.createElement("a");
        const file = new Blob([document.getElementById('emailText').value], {type: 'text/plain'});
        element.href = URL.createObjectURL(file);
        element.download = "cyberraptor.txt";
        document.body.appendChild(element); // Required for this to work in FireFox
        element.click();

      }





    render() {


        var showDiv = <div>Loading ...</div>



        if (this.state.screen === 3) {
            var teamContent = ""
            var downloadContent = ""

            teamContent += "<div style=\"font-size: 14px;\"><br></br>" + this.state.emailHeader.replace(/(?:\\[rn]|[\r\n])/g,"<br>") + "<br></br></div>"
            teamContent += "<div style=\"font-size: 14px;\"><b>Holdover assignments:</b><br></br></div>"

            downloadContent += this.state.emailHeader + "\r\n"
            downloadContent += "Holdover assignments:" + "\r\n\r\n"


            for (var indexI in this.state.result.team) {

                var eachTeam = this.state.result.team[indexI]
                var patientArray = this.state.assigned.filter(Record => Record.Team === eachTeam.name)

                var colorTeam = "black"
                /*
                if (patientArray.length > 2) {
                  colorTeam = "red"
                }
                */
                var dutyString = ""
                if (eachTeam.duty.length > 0) {
                    dutyString += "call cycle: " + eachTeam.duty + ", "
                }

                teamContent += "<div style=\"font-size: 14px;color: " + colorTeam + ";\"><b><u>" + eachTeam.name + "&nbsp;(" + dutyString + "total census " + eachTeam.totalCensus + " + " + patientArray.length + " holdovers)</u></b><br></br></div>"
                downloadContent += eachTeam.name + " (" + dutyString + "total census " + eachTeam.totalCensus + " + " + patientArray.length + " holdovers)\r\n"
                downloadContent += "-------------------------------------------------------------------------\r\n"




                if (patientArray.length > 0) {
                    for (var y=0;y<patientArray.length;y++){

                        /*
                        var minutes = 15 * y 
                        var totalMinutes = 495 + minutes
                        if (this.state.result.todayDay === 2) {
                            totalMinutes = 510 + minutes
                        } 
                        var minutePart = totalMinutes % 60
                        var hourPart = (totalMinutes - minutePart) / 60

                        var endMinutePart = (totalMinutes + 15) % 60
                        var endHourPart = (totalMinutes + 15 - endMinutePart) / 60

                        var signoutTime = hourPart + ":" + minutePart + "-" + endHourPart + ":" + endMinutePart + ": "


                        if (eachTeam.appTeam) {
                            signoutTime = ""
                        }

    */
                        var oneLinerText = ""
                        var oneLinerDownloadText = "\r\n\r\n"
                        if (patientArray[y].OneLiner != undefined) {
                            oneLinerText = "<br><font style=\"color: blue;\">" + patientArray[y].OneLiner + "</font>"
                            oneLinerDownloadText = patientArray[y].OneLiner + "\r\n\r\n"
                        }


                        //oneLinerText = "<br></br><font style=\"color: blue;\">One Liner Summary</font>"


                        var signoutString = ""
                        var signoutDownload = ""
                        /*
                        if (patientArray[y].crane) {
                            signoutString = patientArray[y].signoutTimeDetail
                            signoutDownload = patientArray[y].signoutTimeDetail
                        } else {
                            //if (!patientArray[y].appTeam) {
                                signoutString = "<div>Signout start at " + patientArray[y].signoutTimeDetail + ", please page " + patientArray[y].FromTeam + " before 7:30am</div>"
                                signoutDownload = "Signout start at " + patientArray[y].signoutTimeDetail + ", please page " + patientArray[y].FromTeam + " before 7:30am\r\n"
                            //}
                        }
                        */

                        var fromTeam = patientArray[y].FromTeam

                        if (fromTeam == "Cardiology Gen Night Hospitalist Inpatient (Crane)") {
                            fromTeam = "Crane"
                        }
                        if (fromTeam == "Cardiology Gen Swing Hospitalist Inpatient (Raven)") {
                            fromTeam = "Raven"
                        }

                        teamContent += "<div style=\"font-size: 12px;\">" + signoutString + "<font style=\"color: #8B4513;\"><b>MRN: " + patientArray[y].MRN + ",&nbsp;" + patientArray[y].Name + ",&nbsp;" + patientArray[y].Location + "</b></font> - from " + fromTeam + oneLinerText + "<br></br></div>"
                        downloadContent += signoutDownload + " MRN: " + patientArray[y].MRN + ", " + patientArray[y].Name + ", " + patientArray[y].Location + " - from " +  fromTeam + "\r\n" + oneLinerDownloadText

                    }
                } else {
                    teamContent += "<div style=\"font-size: 12px;\">No distribution<br></br></div>"
                    downloadContent += "No distribution\r\n\r\n"
                }

            }

            teamContent += "<div><br></br></div>"
            downloadContent += "\r\n"

            //teamContent += "<div style=\"font-size: 14px;\"><b>Non-ICU Holdover Signout Schedule:</b><br></br></div>"
            //teamContent += "<div style=\"font-size: 12px;\">Early Signout <ul><li>APPs please page ________ at 7am for holderover signout</li></ul><br></br></div>"

            //teamContent += "<div style=\"font-size: 14px;\"><b>ICU Holdover & ICU Rouding Schedule:</b><br></br></div>"

            //teamContent += "<div style=\"font-size: 14px;\"><b>ICU Established Patient Rounding Schedule</b><br></br></div>"
            teamContent += "<div style=\"font-size: 14px;\"><b>Total # of holdovers = " + this.state.assigned.length + "</b></div>"


            //downloadContent += "Non-ICU Holdover Signout Schedule:\r\n"
            //downloadContent += "Early Signout\r\n - APPs please page ________ at 7am for holderover signout\r\n\r\n"
            //downloadContent += "ICU Holdover & ICU Rouding Schedule:\r\n\r\n"
            //downloadContent += "ICU "
            downloadContent += "Total # of holdovers = " + this.state.assigned.length + "\r\n"

            var admitTeam = ""

            /*
            admitTeam += "<li>Cat:</li>"
            downloadContent += " - Cat:" + "\r\n"

            admitTeam += "<li>Carebear:</li>"
            downloadContent += " - Carebear:" + "\r\n"
            */

            for (var index in this.state.result.admit) {
                var admitTeamInfo = this.state.result.admit[index]
                var teamName = admitTeamInfo.name

                if (teamName == "Cardiology Gen Night Hospitalist Inpatient (Crane)") {
                    teamName = "Crane"
                }
                if (teamName == "Cardiology Gen Swing Hospitalist Inpatient (Raven)") {
                    teamName = "Raven"
                }

                admitTeam += "<li>" + teamName + ":" + admitTeamInfo.totalCensus + "</li>"
                downloadContent += " - " + teamName + ":" + admitTeamInfo.totalCensus + "\r\n"
            }

            teamContent += "<div style=\"font-size: 12px;\"><ul>" + admitTeam + "</ul></div>"


            //var emailHtml = "<div style=\"font-size: 14px\">Good morning Everyone<br></br>Signout will start at " + this.state.signoutTime + " (8:00am on Thursday) today<br></br><div style=\"width: 80%\">" + this.state.emailHeader.replace(/(?:\r\n|\r|\n)/g, '<br>') + "</div><br><br>" + amionContentText + "<br></br>" + teamContent + this.state.emailFooter.replace(/(?:\r\n|\r|\n)/g, '<br>').replace(/ /g, "\u00a0") + "</div>"


            showDiv = <div>
                <div>
                    <button onClick={this.copyFormatted(teamContent)} style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow"}}>Copy Html</button>
                    &nbsp; &nbsp;
                    <button onClick={(e) => this.downloadPdf(teamContent)} style={{height: "30px", width: "120px", fontSize: "16px", background: "blue"}}>Download</button>
                    <br></br><br></br>
                </div>
                <textarea id="emailText" name="emailText" rows="10" cols="150" style={{display: "none", fontSize: "12px", lineHeight: "24px"}} ref={(textarea) => this.textArea = textarea}>
                   {downloadContent}
                </textarea>
                <div dangerouslySetInnerHTML={{ __html: teamContent }} />

            </div>
        }



        if (this.state.screen === 2){
            var teamContent = []
            teamContent.push(<div style={{fontSize: "16px", color: "green"}}><br></br><u><b>Please assign the following patients</b></u></div>)
            var team2 = []



            this.state.result.team.map(Record => team2.push(<option key={Record.name} value={Record.name}>{Record.name}</option>))


            for (var indexI in this.state.remainPatients) {
                var patient = this.state.remainPatients[indexI]
                var teamName = ""

                var fromTeam = patient.Team

                if (fromTeam == "Cardiology Gen Night Hospitalist Inpatient (Crane)") {
                    fromTeam = "Crane"
                }
                if (fromTeam == "Cardiology Gen Swing Hospitalist Inpatient (Raven)") {
                    fromTeam = "Raven"
                }

                teamName = "from " + fromTeam
                teamContent.push(<div style={{fontSize: "14px"}}><font style={{color: "#8B4513"}}><b>MRN: {patient.MRN} {patient.Name} {patient.Age} {patient.Sex}</b></font><font style={{color: "#9B870C", fontSize: "14px"}}> - <u>{teamName}</u></font><br></br><font style={{color: 'blue'}}>{patient.OneLiner}</font><div>move to <select id={"move_" + patient.MRN}>{team2}</select> <button style={{marginLeft: '12px'}} onClick={this.runMoveToAssign} value={patient.MRN}>submit</button></div><br></br></div>)


            }

            teamContent.push(<hr></hr>)

            for (var indexI in this.state.result.team) {

                var eachTeam = this.state.result.team[indexI]
                var patientArray = this.state.assigned.filter(Record => Record.Team === eachTeam.name)

                var colorTeam = "black"
                /*
                if (patientArray.length > 2) {
                  colorTeam = "red"
                }
                */
                teamContent.push(<div style={{color: colorTeam, fontSize: "14px"}}><br></br><u>{eachTeam.name}({eachTeam.totalCensus} total pts {eachTeam.duty})</u></div>)

                for (var y=0;y<patientArray.length;y++){
                    var team = []
                    this.state.result.team.map(Record => team.push(<option key={Record.name} value={Record.name}>{Record.name}</option>))
                    //this.state.result.team.filter(Filter => Filter.name != eachTeam.name ).map(Record => team.push(<option key={Record.name} value={Record.name}>{Record.name}</option>))

/*
                    var minutes = 15 * y 
                    var totalMinutes = 495 + minutes
                    if (this.state.result.todayDay === 2) {
                        totalMinutes = 510 + minutes
                    } 
                    var minutePart = totalMinutes % 60
                    var hourPart = (totalMinutes - minutePart) / 60

                    var endMinutePart = (totalMinutes + 15) % 60
                    var endHourPart = (totalMinutes + 15 - endMinutePart) / 60

                    var signoutTime = hourPart + ":" + minutePart + "-" + endHourPart + ":" + endMinutePart + ": "


                    if (eachTeam.appTeam) {
                        signoutTime = ""
                    }
*/
                    var signoutString = ""
                    /*
                    if (patientArray[y].crane) {
                        signoutString = patientArray[y].signoutTimeDetail
                    } else {
                        //if (!patientArray[y].appTeam) {
                            signoutString = <div>Signout start at {patientArray[y].signoutTimeDetail}, please page {patientArray[y].FromTeam} before 7:30am</div>
                        //}
                    }
*/

                    var fromTeam = patientArray[y].FromTeam

                    if (fromTeam == "Cardiology Gen Night Hospitalist Inpatient (Crane)") {
                        fromTeam = "Crane"
                    }
                    if (fromTeam == "Cardiology Gen Swing Hospitalist Inpatient (Raven)") {
                        fromTeam = "Raven"
}


                    teamContent.push(<div style={{fontSize: "12px"}}>{signoutString}<font style={{color: "#8B4513"}}><b>MRN: {patientArray[y].MRN} {patientArray[y].Name}</b></font> - Sign out from {fromTeam}<br></br><font style={{color: 'blue'}}>{patientArray[y].OneLiner ? patientArray[y].OneLiner : ""}</font><div>move to <select id={"move_" + patientArray[y].MRN}>{team}</select> <button style={{marginLeft: '12px'}} onClick={this.runMove} value={patientArray[y].MRN}>submit</button></div></div>)

                }

            }


            var disableConfirm = false
            if (this.state.remainPatients.length > 0)
            disableConfirm = true


            showDiv =              
            <div style={{marginTop: "40px"}}>
                {teamContent}
                <br></br>
                <button disabled={disableConfirm} style={{height: "30px", width: "100px", fontSize: "16px"}} onClick={this.runConfirm}>Confirm</button>
            </div>

        }


        if (this.state.result.todayDay !== undefined && this.state.screen === 1) {

            //var signoutTime = "8:15am"
            //if (this.state.result.todayDay === 2) {
                //signoutTime = "8:30am"
            //} 

            /*
            <div>
            Good morning,<br></br>
        </div>*/

            var appAdmittingDay = this.state.result.appAdmittingDay
            var whatDay = "resident"
            if (appAdmittingDay) {
                whatDay = "APP"
            }

            var totalDistribute = 0
            for (var index in this.state.result.admit) {
                totalDistribute += this.state.result.admit[index].patients.length
            }
            var residentBlockNumber = this.state.result.block.filter(Rec => Rec.type === "R2R3")[0].block
            var internBlockNumber = this.state.result.block.filter(Rec => Rec.type === "R1")[0].block
            var ucblockString = ""
            ucblockString += "Resident Block#: " + residentBlockNumber + "\r\n" + "Intern Block#: " + internBlockNumber


            var attendingString = ""
            attendingString += "Attending on call: " + this.state.result.amion.filter(rec => rec.team == "Gen Cards Attending on Call")[0].name + "\r\n"
            if (appAdmittingDay) {
                attendingString += "Noncall attending: " + this.state.result.amion.filter(rec => rec.team == "Gen Cards Team AB")[0].name + "\r\n"
            } else {
                attendingString += "Noncall attending: " + this.state.result.amion.filter(rec => rec.team == "Gen Cards Team CDE")[0].name + "\r\n"
            }
            attendingString += "APP 1: " + this.state.result.amion.filter(rec => rec.team == "Gen Cards APP1")[0].name + "\r\n"
            attendingString += "APP 2: " + this.state.result.amion.filter(rec => rec.team == "Gen Cards APP2")[0].name + "\r\n"
            attendingString += "APP 3: " + this.state.result.amion.filter(rec => rec.team == "Gen Cards APP3")[0].name + "\r\n"
            attendingString += "Raven today: " + this.state.result.amionHosp.filter(rec => rec.team == "Raven")[0].name + "\r\n"
            attendingString += "Crane tonight: " + this.state.result.amionHosp.filter(rec => rec.team == "Night Crane")[0].name + "\r\n"




            var showDiv = 
                <div>

                    <br></br>
                    Email Header:
                    <div>
                        <textarea id="emailHeader" name="emailHeader" rows="10" cols="100">
                        {"Good morning all,\r\n\r\n" +
                        "Today is a " + whatDay + " admitting day.\r\n\r\n" +
                        ucblockString + "\r\n\r\n" +
                        attendingString + "\r\n" + 
                        "There are " + totalDistribute + " patients to distribute this morning. Signout will start at 7am for all holdovers."
                        }
                        </textarea>
                    </div>

                    <div style={{marginTop: "40px"}}>
                        <button style={{height: "30px", width: "100px", fontSize: "16px"}} onClick={this.runManually}>Next</button>
                    </div>

                </div>
        }


        return (
            <div style={{minHeight: "500px", marginLeft: "50px"}}>{showDiv}</div>
        )


    }


}

export default Cardiology;
